#!/bin/bash
# =================================================================
# lang.sh — Локализация (RU / EN)
# =================================================================

VWN_CONF="/usr/local/etc/xray/vwn.conf"
VWN_LANG="${VWN_LANG:-}"

# Загружаем сохранённый язык если не задан
if [ -z "$VWN_LANG" ]; then
    [ -f "$VWN_CONF" ] && source "$VWN_CONF"
    VWN_LANG="${VWN_LANG:-ru}"
fi

selectLang() {
    clear
    echo "┌─────────────────────────────────┐"
    echo "│   Select language / Выберите язык│"
    echo "├─────────────────────────────────┤"
    echo "│   1) 🇷🇺  Русский                │"
    echo "│   2) 🇬🇧  English                │"
    echo "└─────────────────────────────────┘"
    read -rp "Choice / Выбор [1]: " _lang_choice
    case "${_lang_choice:-1}" in
        2) VWN_LANG="en" ;;
        *) VWN_LANG="ru" ;;
    esac
    mkdir -p "$(dirname "$VWN_CONF")"
    # Сохраняем, не трогая остальные настройки
    if [ -f "$VWN_CONF" ]; then
        sed -i '/^VWN_LANG=/d' "$VWN_CONF"
    fi
    echo "VWN_LANG=${VWN_LANG}" >> "$VWN_CONF"
    export VWN_LANG
}

